class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next
def remove_nth_from_end(head, n):
    dummy = ListNode(0, head)
    first = second = dummy
    for _ in range(n):
        first = first.next
    while first and first.next:
        first = first.next
        second = second.next
    second.next = second.next.next if second.next else None
    return dummy.next

